import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversalExample {

    public static void main(String[] args) {
        String baseDirectory = "/var/www/files/";
        String userInput = "../../../../../etc/passwd"; // User input that can be manipulated

        // Resolve the full path using Paths.get() to prevent directory traversal
        String resolvedPath = Paths.get(baseDirectory, userInput).normalize().toString();

        if (!resolvedPath.startsWith(baseDirectory)) {
            System.out.println("Invalid file path.");
            return;
        }

        try {
            File file = new File(resolvedPath);
            FileInputStream fis = new FileInputStream(file);

            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }

            fis.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

